mapper.select:
select from course c left join teacher t on c.teacher_id = t.id
and c.name like concat('%', #{name}, '%')
and c.code like concat('%', #{code}, '%')
and c.teacher_id = #{teacherId}
and c.status = #{status}
order by c.create_time desc

mapper.update:
update course
name = #{name}, code = #{code}, teacher_id = #{teacherId}, description = #{description}, credit = #{credit}, hours = #{hours}, status = #{status},
where id = #{id}
